{
  "schemaVersion": 2,
  "id": "cobalt-dusk-pack",
  "name": "Cobalt Dusk Pack",
  "version": "1.0.0",
  "entry": null,
  "pluginType": "theme-pack",
  "capabilities": [
    "theme.style"
  ],
  "platforms": [
    "desktop",
    "web"
  ],
  "requiresRestart": false,
  "experimental": false,
  "minAppVersion": "0.6.0",
  "maxAppVersion": null,
  "permissions": {
    "theme": {
      "register": true
    }
  },
  "contributes": {
    "theme": {
      "style": [
        {
          "file": "theme/style/cobalt-dusk-pack.css",
          "label": "Cobalt Dusk",
          "description": "Crisp cobalt palette tuned for code-heavy notes."
        }
      ],
      "snippets": [],
      "tokens": [],
      "defaultEnable": {
        "style": false
      }
    },
    "commands": [],
    "preferencesSections": [],
    "panels": []
  }
}

/**
 * Cobalt Dusk — external CSS theme
 *
 * Deep cobalt dark palette with crisp code blocks and contrasty links.
 */

html[data-theme='dark'] {
  --surface-app: #111827;
  --surface-panel: rgba(17, 24, 39, 0.94);
  --surface-editor: #0f172a;
  --surface-preview: #0b1222;
  --surface-hover: rgba(96, 165, 250, 0.12);
  --surface-elevated: #1e293b;
  --text-primary: #e5ecff;
  --text-secondary: #a9b9d6;
  --text-muted: #8ea0bd;
  --text-tertiary: #8ea0bd;
  --border-subtle: rgba(229, 236, 255, 0.11);
  --border-strong: rgba(229, 236, 255, 0.18);
  --accent: #60a5fa;
  --link: #7db6ff;
  --link-hover: #a6cbff;
  --link-visited: #c4b5fd;
  --focus-ring: rgba(125, 177, 255, 0.26);
  --code-bg: #0e1a31;
  --code-gutter-fg: #8ea0bd;
  --code-gutter-bg: #0a1428;
  --inline-code-bg: #1a2a49;
  --shadow-soft: 0 1px 2px rgba(0, 0, 0, 0.45);
  --shadow-panel: 0 14px 42px rgba(0, 0, 0, 0.55);
}

html[data-theme='light'] {
  --surface-app: #eef4ff;
  --surface-panel: rgba(255, 255, 255, 0.94);
  --surface-editor: #ffffff;
  --surface-preview: #f5f8ff;
  --surface-hover: rgba(37, 99, 235, 0.08);
  --surface-elevated: #ffffff;
  --text-primary: #1a2742;
  --text-secondary: #4e6285;
  --text-muted: #6f83a3;
  --text-tertiary: #6f83a3;
  --border-subtle: rgba(26, 39, 66, 0.11);
  --border-strong: rgba(26, 39, 66, 0.17);
  --accent: #2563eb;
  --link: #1d4ed8;
  --link-hover: #1e40af;
  --link-visited: #6d28d9;
  --focus-ring: rgba(37, 99, 235, 0.22);
  --code-bg: #eff4ff;
  --code-gutter-fg: #6f83a3;
  --code-gutter-bg: #e3ecff;
  --inline-code-bg: #e8f0ff;
  --shadow-soft: 0 1px 2px rgba(26, 39, 66, 0.08);
  --shadow-panel: 0 10px 30px rgba(26, 39, 66, 0.12);
}

.editor-tabs-strip {
  box-shadow: inset 0 -1px 0 color-mix(in srgb, var(--border-subtle) 92%, transparent);
}

.preview-pane.markdown-visual-editor .ProseMirror a.pm-link-inline {
  text-decoration-thickness: 1.5px;
  text-underline-offset: 3px;
}

.preview-pane.markdown-visual-editor .ProseMirror .pm-code-block-surface {
  box-shadow:
    inset 0 0 0 var(--hairline) color-mix(in srgb, var(--accent) 18%, var(--border-subtle)),
    var(--shadow-panel);
}
